mapper.select:
SELECT g.goodsname AS goodsname, IFNULL(SUM(i.number), 0) AS totalNumber, i.inportprice AS price, IFNULL(SUM(i.inportprice * i.number), 0) AS totalAmount FROM bus_inport i LEFT JOIN bus_goods g ON i.goodsid = g.id
i.isdelete = 0
AND DATE(i.inporttime) >= #{startDate}
AND DATE(i.inporttime) <= #{endDate}
GROUP BY i.goodsid, i.inportprice ORDER BY totalAmount DESC

SELECT i.orderno AS orderNo, MAX(i.providerid) AS providerId, IFNULL(MAX(p.providername), '') AS providerName, MAX(i.inporttime) AS inporttime, MAX(i.operateperson) AS operateperson, MAX(i.remark) AS remark, SUM(CASE WHEN IFNULL(i.order_status, 0) = 0 THEN i.number ELSE 0 END) AS totalNumber, SUM(CASE WHEN IFNULL(i.order_status, 0) = 0 THEN i.inportprice * i.number ELSE 0 END) AS totalAmount, (SELECT IFNULL(SUM(al.number), 0) FROM bus_inport_log al WHERE al.order_no = i.orderno AND al.type = 'add') AS addedNumber, (SELECT IFNULL(SUM(rl.number), 0) FROM bus_inport_log rl WHERE rl.order_no = i.orderno AND rl.type = 'return') AS returnedNumber, COUNT(*) AS itemCount, MIN(CASE WHEN IFNULL(i.order_status, 0) = 1 THEN 1 ELSE 0 END) AS orderStatus FROM bus_inport i LEFT JOIN bus_provider p ON p.id = i.providerid
i.isdelete = 0 AND i.orderno IS NOT NULL
AND i.providerid = #{vo.providerid}
AND i.inporttime >= #{vo.startTime}
AND i.inporttime <= #{vo.endTime}
GROUP BY i.orderno ORDER BY MAX(i.inporttime) DESC

SELECT l.id AS id, l.order_no AS orderNo, l.type AS type, IFNULL(p.providername, '') AS providerName, IFNULL(g.goodsname, '') AS goodsName, IFNULL(g.size, '') AS goodsSize, l.number AS number, l.price AS price, l.price * l.number AS totalAmount, l.operate_person AS operatePerson, IFNULL(DATE_FORMAT(l.operate_time, '%Y-%m-%d %H:%i:%s'), '') AS operateTime, l.remark AS remark FROM bus_inport_log l LEFT JOIN bus_provider p ON p.id = l.provider_id LEFT JOIN bus_goods g ON g.id = l.goods_id
AND l.provider_id = #{vo.providerid}
AND l.order_no = #{vo.orderNo}
AND l.type = #{vo.recordType}
AND l.operate_time >= #{vo.startTime}
AND l.operate_time <= #{vo.endTime}
ORDER BY l.operate_time DESC
